def judgeCircle(self, moves: str) -> bool:
    move_count = len(moves)
    direction_count = {}
    for move in moves:
        if move in ['U', 'D']:
            direction_count[move] += 1
        elif move in ['L', 'R']:
            direction_count[move] -= 1
            if direction_count[move] < 0:
                return False
    if direction_count['U'] == direction_count['D'] and direction_count['L'] == direction_count['R']:
        return True
    return False

